fn growth_capped_at_max() {
        let mut b = AdaptiveBatcher::new(1_000_000_000, 56_000_000, 0.15);
        let max = b.max_batch;
        for _ in 0..20 {
            b.report_success();
        }
        assert_eq!(b.batch_size(), max);
    }
fn fixed_batcher_does_not_grow() {
        let mut b = AdaptiveBatcher::fixed(4);
        for _ in 0..100 {
            b.report_success();
        }
        assert_eq!(b.batch_size(), 4);
    }
